:&lt;/span&gt;&lt;span style=&#34;color:#AB5959;--shiki-dark:#CB7676&#34;&gt;/&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;usr&lt;/span&gt;&lt;span style=&#34;color:#AB5959;--shiki-dark:#CB7676&#34;&gt;/&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;sbin&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;:&lt;/span&gt;&lt;span style=&#34;color:#AB5959;--shiki-dark:#CB7676&#34;&gt;/&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;usr&lt;/span&gt;&lt;span style=&#34;color:#AB5959;--shiki-dark:#CB7676&#34;&gt;/&lt;/span&gt;&lt;span style=&#34;color:#998418;--shiki-dark:#B8A965&#34;&gt;bin&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;:&lt;/span&gt;&lt;span style=&#34;color:#AB5959;--shiki-dark:#CB7676&#34;&gt;/&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;sbin&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;:&lt;/span&gt;&lt;span style=&#34;color:#AB5959;--shiki-dark:#CB7676&#34;&gt;/&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;binUVICORN_HOST&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;=&lt;/span&gt;&lt;span style=&#34;color:#2F798A;--shiki-dark:#4C9A91&#34;&gt;0.0&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;.&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;0&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;.&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;0PYTHON_VERSION&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;=&lt;/span&gt;&lt;span style=&#34;color:#2F798A;--shiki-dark:#4C9A91&#34;&gt;3.13&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;.&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;11UVICORN_PORT&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;=&lt;/span&gt;&lt;span style=&#34;color:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic&#34;&gt;8000PWD&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;=&lt;/span&gt;&lt;span style=&#34;color:#AB5959;--shiki-dark:#CB7676&#34;&gt;/&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;appFLAG&lt;/span&gt;&lt;span style=&#34;color:#999999;--shiki-dark:#666666&#34;&gt;=&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;FhCTF&lt;/span&gt;&lt;span style=&#34;color:#2993a3;--shiki-dark:#5eaab5&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span style=&#34;color:#393A34;--shiki-dark:#DBD7CAEE&#34;&gt;N0t_s4f3_t0_ou7put_th3_err0r_m5g&lt;/span&gt;&lt;span style=&#34;color:#2993a3;--shiki-dark:#5eaab5&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span style=&#34;color:#AB5959;--shiki-dark:#CB7676&#34;&gt;^&lt;/span&gt;&lt;/span&gt;&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;得到flag &lt;code&gt;FhCTF&amp;#123;N0t_s4f3_t0_ou7put_th3_err0r_m5g&amp;#125;&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;分享圖庫-revenge&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分享圖庫-revenge&#34;&gt;#&lt;/a&gt; 分享圖庫 Revenge&lt;/h3&gt;
&lt;p&gt;分享圖庫的進階題&lt;/p&gt;
&lt;p&gt;這我真不會解，檔案照樣可以上傳但他被只當成png來解讀&lt;/p&gt;
&lt;pre class=&#34;shiki shiki-themes vitesse-light vitesse-dark&#34; style=&#34;background-color:#ffffff;--shiki-dark-bg:#121212;color:#393a34;--shiki-dark:#dbd7caee&#34; tabindex=&#34;0&#34;&gt;&lt;code class=&#34;language-text&#34;&gt;&lt;span class=&#34;line&#34;&gt;&lt;span&gt;�PNG  IHDR%�V�PLTE������ pHYs���+ IDAT�c`�qd�IEND�B`�&lt;/span&gt;&lt;/span&gt;&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;又是我的朋友&lt;br /&gt;
他找到了一個&lt;s&gt;超級搞笑&lt;/s&gt;的解法&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;image-14.png&#34; alt=&#34;alt text&#34; /&gt;&lt;/p&gt;
&lt;p&gt;題目有漏洞（&lt;s&gt;當然也可能是這麼設計的畢竟是雜項:)))&lt;/s&gt;&lt;/p&gt;
&lt;h2 id=&#34;web&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#web&#34;&gt;#&lt;/a&gt; Web&lt;/h2&gt;
&lt;h3 id=&#34;welcome-to-cybersecurity-jungle&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#welcome-to-cybersecurity-jungle&#34;&gt;#&lt;/a&gt; Welcome to Cybersecurity Jungle&lt;/h3&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;image-15.png&#34; alt=&#34;alt text&#34; /&gt;&lt;/p&gt;
&lt;p&gt;基於新手題與題目敘述先查看cookie&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; src=&#34;image-16.png&#34; alt=&#34;alt text&#34; /&gt;&lt;/p&gt;
&lt;p&gt;cookie 名稱 &lt;code&gt;aXNGbGFnU2hvdzJ1&lt;/code&gt; 進行 Base64 解碼：&lt;br /&gt;
解碼結果：&lt;code&gt;isFlagShow2u&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;44G144GJ44O844KL44GZ&lt;/code&gt; Base64 解碼後得到日文假名：&lt;br /&gt;
解碼結果：ふぉーるす（是日文假名寫法的 false）&lt;br /&gt;
將日文假名的 true轉 Base64 後，得到：&lt;br /&gt;
&lt;code&gt;44Go44GF44KL44O8&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;修改cookie後重整畫面即可得到flag&lt;/p&gt;

 &lt;blockquote&gt;
&lt;p&gt;本篇為訓練期間／歷史實作的 &lt;strong&gt;Raw Code 紀錄&lt;/strong&gt;，當時未撰寫完整解題說明，保留原始寫法。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;tqc-程式語言python-409-得票數計算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tqc-程式語言python-409-得票數計算&#34;&gt;#&lt;/a&gt; TQC+ 程式語言Python 409 得票數計算&lt;/h1&gt;
